namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("3105559876");

        Assert.StartsWith("(310)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("3105559876");

        Assert.EndsWith("9876", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ──

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ReturnsCorrectGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDearAndTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_ContainsName()
    {
        var result = _formatter.BuildGreeting("Williams", "Prof.");

        Assert.Contains("Williams", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ──

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_ComplexTitle_ContainsOnlyValidChars()
    {
        var result = _formatter.GenerateSlug("My Article: Part 1!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_NoLeadingOrTrailingHyphens()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");

        Assert.StartsWith("h", result);
        Assert.EndsWith("d", result);
    }

    [TestMethod]
    [DataRow("C# Is Great", "c-is-great")]
    [DataRow("  spaces  everywhere  ", "spaces-everywhere")]
    [DataRow("already-slugged", "already-slugged")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string input, string expected)
    {
        Assert.AreEqual(expected, _formatter.GenerateSlug(input));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ──

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(42m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWith00()
    {
        var result = _formatter.FormatCurrency(50m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_MatchesPattern()
    {
        var result = _formatter.FormatCurrency(1234.5m, "$");

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }

    [TestMethod]
    [DataRow(0, "$0.00")]
    [DataRow(99.9, "$99.90")]
    [DataRow(-5.5, "$-5.50")]
    public void FormatCurrency_VariousAmounts_ReturnsExpected(double amount, string expected)
    {
        Assert.AreEqual(expected, _formatter.FormatCurrency((decimal)amount));
    }
}

